  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import { useLocation, useNavigate } from 'react-router-dom';
  3→import { learningApi } from '../api';
  4→import { API_BASE_URL, authFetch } from '../api/client';
  5→import AgentCanvasSections from '../components/agent/AgentCanvasSections';
  6→import SelectionAskChip from '../components/agent/SelectionAskChip';
  7→import AgentStatusDots from '../components/agent/AgentStatusDots';
  8→import { DEFAULT_HOME_ICON_KEY } from '../constants/homeIconCatalog';
  9→import { useTutor, useUser } from '../contexts';
 10→import useAgentControlOrchestrator from '../hooks/useAgentControlOrchestrator';
 11→import useSelectionAskPrompt from '../hooks/useSelectionAskPrompt';
 12→import buildActionCatalog from '../utils/agent/buildActionCatalog';
 13→import buildUiSnapshot from '../utils/agent/buildUiSnapshot';
 14→import composeCanvasState from '../utils/agent/composeCanvasState';
 15→
 16→const HORIZONTAL_SWIPE_THRESHOLD_PX = 86;
 17→const SWIPE_TOAST_DURATION_MS = 1500;
 18→const SEARCH_TOGGLE_KEY = 'adelie_agent_web_search';
 19→const REVIEW_META_PREFIX = 'review_meta:';
 20→
 21→function readSearchToggleFromStorage(mode = 'home') {
 22→  try {
 23→    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
 24→    if (value === '1') return true;
 25→    if (value === '0') return false;
 26→    return mode === 'stock';
 27→  } catch {
 28→    return mode === 'stock';
 29→  }
 30→}
 31→
 32→function buildReviewTarget(mode, contextPayload) {
 33→  if (mode === 'home') {
 34→    const dateRaw = String(contextPayload?.date || '').replace(/\D/g, '');
 35→    const dateValue = Number(dateRaw);
 36→    if (dateRaw.length === 8 && Number.isFinite(dateValue)) {
 37→      return {
 38→        contentType: 'briefing',
 39→        contentId: dateValue,
 40→      };
 41→    }
 42→    return null;
 43→  }
 44→
 45→  const caseId = Number(contextPayload?.case_id || 0);
 46→  if (Number.isInteger(caseId) && caseId > 0) {
 47→    return {
 48→      contentType: 'case',
 49→      contentId: caseId,
 50→    };
 51→  }
 52→  return null;
 53→}
 54→
 55→function getContextByMode(mode) {
 56→  try {
 57→    if (mode === 'home') {
 58→      const enriched = sessionStorage.getItem('adelie_home_context_enriched');
 59→      if (enriched) return JSON.parse(enriched);
 60→
 61→      const base = sessionStorage.getItem('adelie_home_context');
 62→      return base ? JSON.parse(base) : null;
 63→    }
 64→
 65→    if (mode === 'education') {
 66→      const education = sessionStorage.getItem('adelie_education_context');
 67→      return education ? JSON.parse(education) : null;
 68→    }
 69→  } catch {
 70→    // ignore storage parsing error
 71→  }
 72→
 73→  return null;
 74→}
 75→
 76→function getVisibleSectionsByMode(mode) {
 77→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
 78→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
 79→  if (mode === 'my') return ['profile', 'settings'];
 80→  return ['asset_summary', 'learning_schedule', 'issue_card', 'conversation_cards'];
 81→}
 82→
 83→function buildContextSummary(mode, contextPayload) {
 84→  if (mode === 'stock') {
 85→    const stockName = contextPayload?.stock_name || '선택 종목';
 86→    const stockCode = contextPayload?.stock_code ? ` (${contextPayload.stock_code})` : '';
 87→    const holdingText = contextPayload?.has_holding === undefined
 88→      ? ''
 89→      : contextPayload.has_holding ? ' · 보유 중' : ' · 미보유';
 90→    return `${stockName}${stockCode}${holdingText}`;
 91→  }
 92→
 93→  if (mode === 'education') {
 94→    return contextPayload?.selected_date
 95→      ? `${contextPayload.selected_date} 학습 기준`
 96→      : '교육 화면 컨텍스트';
 97→  }
 98→
 99→  return contextPayload?.market_summary || '홈 화면 컨텍스트';
100→}
101→
102→function buildAgentContextEnvelope({ mode, pathname, contextPayload, userPrompt, searchEnabled = false }) {
103→  const uiSnapshot = contextPayload?.ui_snapshot || buildUiSnapshot({
104→    pathname,
105→    mode,
106→    visibleSections: getVisibleSectionsByMode(mode),
107→    selectedEntities: {
108→      stock_code: contextPayload?.stock_code || null,
109→      stock_name: contextPayload?.stock_name || null,
110→      date_key: contextPayload?.selected_date || contextPayload?.date || null,
111→      case_id: contextPayload?.case_id || null,
112→    },
113→    filters: {
114→      tab: mode,
115→    },
116→    portfolioSummary: contextPayload?.portfolio_summary || null,
117→  });
118→
119→  const actionCatalog = Array.isArray(contextPayload?.action_catalog)
120→    ? contextPayload.action_catalog
121→    : buildActionCatalog({ pathname, mode, stockContext: contextPayload });
122→
123→  return {
124→    mode,
125→    context: contextPayload,
126→    ui_snapshot: uiSnapshot,
127→    action_catalog: actionCatalog,
128→    interaction_state: {
129→      source: 'agent_canvas',
130→      mode,
131→      route: pathname,
132→      focused_prompt: userPrompt || null,
133→      search_enabled: Boolean(searchEnabled),
134→    },
135→  };
136→}
137→
138→export default function AgentCanvasPage() {
139→  const location = useLocation();
140→  const navigate = useNavigate();
141→  const { settings } = useUser();
142→  const {
143→    messages,
144→    assistantTurns,
145→    isLoading,
146→    isStreamingActive,
147→    canRegenerate,
148→    sessionId,
149→    sessions,
150→    refreshSessions,
151→    sendMessage,
152→    stopGeneration,
153→    regenerateLastResponse,
154→    setContextInfo,
155→    agentStatus,
156→    clearMessages,
157→    loadChatHistory,
158→  } = useTutor();
159→
160→  const [activeTurnIndex, setActiveTurnIndex] = useState(0);
161→  const [swipeToast, setSwipeToast] = useState('');
162→  const [showContextInfo, setShowContextInfo] = useState(false);
163→  const [horizontalDelta, setHorizontalDelta] = useState(0);
164→  const [isSavingSession, setIsSavingSession] = useState(false);
165→
166→  const processedPromptRef = useRef(new Set());
167→  const resetRef = useRef(new Set());
168→  const restoredSessionRef = useRef(new Set());
169→  const touchStartXRef = useRef(null);
170→  const toastTimerRef = useRef(null);
171→  const prevTurnCountRef = useRef(0);
172→  const selectableContentRef = useRef(null);
173→
174→  const mode = location.state?.mode || (location.state?.stockContext ? 'stock' : 'home');
175→  const stockContext = mode === 'stock' ? (location.state?.stockContext || null) : null;
176→  const initialPrompt = location.state?.initialPrompt || '';
177→  const requestedSessionId = location.state?.sessionId || null;
178→  const useWebSearch = location.state?.useWebSearch ?? readSearchToggleFromStorage(mode);
179→
180→  const chatOptions = useMemo(
181→    () => ({
182→      useWebSearch: Boolean(useWebSearch),
183→      responseMode: 'canvas_markdown',
184→      structuredExtract: true,
185→    }),
186→    [useWebSearch],
187→  );
188→
189→  const contextPayload = useMemo(() => {
190→    if (location.state?.contextPayload) return location.state.contextPayload;
191→    if (mode === 'stock' && location.state?.stockContext) return location.state.stockContext;
192→    return getContextByMode(mode);
193→  }, [location.state, mode]);
194→
195→  const { executeAction, actionCatalog } = useAgentControlOrchestrator({
196→    mode,
197→    stockContext: stockContext || contextPayload,
198→  });
199→
200→  const buildContextInfoForPrompt = useCallback(
201→    (focusedPrompt = '') => {
202→      let ctxType = 'briefing';
203→      let ctxId = null;
204→
205→      if (mode === 'stock') {
206→        ctxType = 'case';
207→        ctxId = contextPayload?.case_id || null;
208→      } else if (mode === 'home') {
209→        const firstCaseId = contextPayload?.keywords?.[0]?.case_id;
210→        if (firstCaseId) {
211→          ctxType = 'case';
212→          ctxId = firstCaseId;
213→        }
214→      }
215→
216→      return {
217→        type: ctxType,
218→        id: ctxId,
219→        stepContent: JSON.stringify(
220→          buildAgentContextEnvelope({
221→            mode,
222→            pathname: location.pathname,
223→            contextPayload,
224→            userPrompt: focusedPrompt,
225→            searchEnabled: useWebSearch,
226→          }),
227→          null,
228→          2,
229→        ),
230→      };
231→    },
232→    [contextPayload, location.pathname, mode, useWebSearch],
233→  );
234→
235→  const turns = useMemo(
236→    () =>
237→      (Array.isArray(assistantTurns) ? assistantTurns : [])
238→        .filter((turn) => typeof turn?.assistantText === 'string')
239→        .map((turn, index) => ({
240→          id: turn.id || `turn-${index}`,
241→          assistantText: turn.assistantText || '',
242→          userPrompt: turn.userPrompt || '',
243→          uiActions: Array.isArray(turn.uiActions) ? turn.uiActions : [],
244→          status: turn.status || 'done',
245→          model: turn.model || null,
246→          structured: turn.structured || null,
247→          guardrailNotice: turn.guardrailNotice || null,
248→          guardrailDecision: turn.guardrailDecision || null,
249→          guardrailMode: turn.guardrailMode || null,
250→        })),
251→    [assistantTurns],
252→  );
253→
254→  useEffect(() => {
255→    const turnCount = turns.length;
256→    if (turnCount === 0) {
257→      prevTurnCountRef.current = 0;
258→      setActiveTurnIndex(0);
259→      return;
260→    }
261→
262→    if (turnCount > prevTurnCountRef.current) {
263→      setActiveTurnIndex(turnCount - 1);
264→    } else {
265→      setActiveTurnIndex((prev) => Math.min(prev, turnCount - 1));
266→    }
267→
268→    prevTurnCountRef.current = turnCount;
269→  }, [turns.length]);
270→
271→  useEffect(
272→    () => () => {
273→      if (toastTimerRef.current) {
274→        clearTimeout(toastTimerRef.current);
275→      }
276→    },
277→    [],
278→  );
279→
280→  const selectedTurn = turns[activeTurnIndex] || null;
281→  const activeSessionId = requestedSessionId || sessionId || null;
282→  const activeSessionMeta = useMemo(
283→    () => (Array.isArray(sessions) ? sessions.find((item) => item.id === activeSessionId) : null),
284→    [activeSessionId, sessions],
285→  );
286→  const isPinnedSession = Boolean(activeSessionMeta?.is_pinned);
287→  const selectedUserPrompt = selectedTurn?.userPrompt || initialPrompt;
288→  const isBrowsingPrevious = turns.length > 0 && activeTurnIndex < turns.length - 1;
289→  const contextSummary = useMemo(() => buildContextSummary(mode, contextPayload), [contextPayload, mode]);
290→
291→  const conversationDepth = useMemo(() => {
292→    if (mode !== 'home') return 0;
293→    const userTurns = (messages || []).filter((message) => message.role === 'user').length;
294→    return Math.min(3, Math.max(1, userTurns || 1));
295→  }, [messages, mode]);
296→
297→  useEffect(() => {
298→    if (!location.state?.resetConversation) return;
299→    if (resetRef.current.has(location.key)) return;
300→
301→    resetRef.current.add(location.key);
302→    clearMessages();
303→  }, [clearMessages, location.key, location.state?.resetConversation]);
304→
305→  useEffect(() => {
306→    if (!requestedSessionId) return;
307→
308→    const restoreKey = `${location.key}:${requestedSessionId}`;
309→    if (restoredSessionRef.current.has(restoreKey)) return;
310→
311→    restoredSessionRef.current.add(restoreKey);
312→    loadChatHistory(requestedSessionId).catch(() => {});
313→  }, [loadChatHistory, location.key, requestedSessionId]);
314→
315→  useEffect(() => {
316→    setContextInfo(buildContextInfoForPrompt(selectedUserPrompt));
317→
318→    return () => {
319→      setContextInfo(null);
320→    };
321→  }, [buildContextInfoForPrompt, selectedUserPrompt, setContextInfo]);
322→
323→  const sendCanvasMessage = useCallback(
324→    (prompt) => {
325→      const normalized = String(prompt || '').trim();
326→      if (!normalized) return;
327→
328→      sendMessage(normalized, settings?.difficulty || 'beginner', {
329→        chatOptions,
330→        contextInfoOverride: buildContextInfoForPrompt(normalized),
331→      });
332→    },
333→    [buildContextInfoForPrompt, chatOptions, sendMessage, settings?.difficulty],
334→  );
335→
336→  useEffect(() => {
337→    const promptKey = `${location.key}:${initialPrompt}`;
338→    if (!initialPrompt || requestedSessionId || processedPromptRef.current.has(promptKey)) return;
339→
340→    processedPromptRef.current.add(promptKey);
341→    sendCanvasMessage(initialPrompt);
342→  }, [initialPrompt, location.key, requestedSessionId, sendCanvasMessage]);
343→
344→  const canvasState = useMemo(
345→    () =>
346→      composeCanvasState({
347→        messages,
348→        mode,
349→        contextPayload,
350→        aiStatus: agentStatus?.text,
351→        userPrompt: selectedUserPrompt,
352→        assistantText: selectedTurn?.assistantText || '',
353→        assistantTurn: selectedTurn,
354→      }),
355→    [
356→      agentStatus?.text,
357→      contextPayload,
358→      messages,
359→      mode,
360→      selectedTurn,
361→      selectedUserPrompt,
362→    ],
363→  );
364→
365→  const reviewTarget = useMemo(
366→    () => buildReviewTarget(mode, contextPayload),
367→    [contextPayload, mode],
368→  );
369→
370→
371→  const showSwipeToast = useCallback((text) => {
372→    setSwipeToast(text);
373→    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
374→    toastTimerRef.current = setTimeout(() => {
375→      setSwipeToast('');
376→    }, SWIPE_TOAST_DURATION_MS);
377→  }, []);
378→
379→  useEffect(() => {
380→    if (turns.length < 2) return;
381→    try {
382→      const seen = localStorage.getItem('adelie_swipe_hint_seen');
383→      if (seen === '1') return;
384→      showSwipeToast('좌우 스와이프 또는 좌우 버튼으로 이전 답변을 탐색할 수 있어요.');
385→      localStorage.setItem('adelie_swipe_hint_seen', '1');
386→    } catch {
387→      // ignore storage errors
388→    }
389→  }, [turns.length, showSwipeToast]);
390→
391→  const moveTurn = useCallback(
392→    (direction) => {
393→      if (turns.length < 2) {
394→        showSwipeToast('이 세션에는 아직 탐색할 이전 답변이 없습니다.');
395→        return;
396→      }
397→      setActiveTurnIndex((prev) => {
398→        const next = prev + direction;
399→        if (next < 0) {
400→          showSwipeToast('가장 이전 답변입니다.');
401→          return prev;
402→        }
403→        if (next > turns.length - 1) {
404→          showSwipeToast('가장 최신 답변입니다.');
405→          return prev;
406→        }
407→        if (direction < 0) showSwipeToast('이전 답변으로 이동했습니다.');
408→        if (direction > 0) showSwipeToast('다음 답변으로 이동했습니다.');
409→        return next;
410→      });
411→    },
412→    [showSwipeToast, turns.length],
413→  );
414→
415→  const handleSwipeTouchStart = useCallback((event) => {
416→    touchStartXRef.current = event.changedTouches?.[0]?.clientX ?? null;
417→    setHorizontalDelta(0);
418→  }, []);
419→
420→  const handleSwipeTouchMove = useCallback((event) => {
421→    if (touchStartXRef.current === null) return;
422→    const currentX = event.changedTouches?.[0]?.clientX;
423→    if (typeof currentX !== 'number') return;
424→    setHorizontalDelta(currentX - touchStartXRef.current);
425→  }, []);
426→
427→  const handleSwipeTouchEnd = useCallback(
428→    (event) => {
429→      if (touchStartXRef.current === null) return;
430→      const endX = event.changedTouches?.[0]?.clientX;
431→      if (typeof endX !== 'number') {
432→        touchStartXRef.current = null;
433→        setHorizontalDelta(0);
434→        return;
435→      }
436→
437→      const deltaX = endX - touchStartXRef.current;
438→      touchStartXRef.current = null;
439→      setHorizontalDelta(0);
440→
441→      if (Math.abs(deltaX) < HORIZONTAL_SWIPE_THRESHOLD_PX) {
442→        showSwipeToast(`조금 더 길게 스와이프 해주세요 (${HORIZONTAL_SWIPE_THRESHOLD_PX}px 이상)`);
443→        return;
444→      }
445→
446→      if (deltaX > 0) {
447→        // 오른쪽 스와이프 -> 과거(이전 답변)
448→        moveTurn(-1);
449→      } else {
450→        // 왼쪽 스와이프 -> 최신(다음 답변)
451→        moveTurn(1);
452→      }
453→    },
454→    [moveTurn, showSwipeToast],
455→  );
456→
457→  const handleActionClick = useCallback(
458→    async (action) => {
459→      if (typeof action === 'string') {
460→        sendCanvasMessage(action);
461→        return;
462→      }
463→
464→      if (action?.type === 'tool' && action?.id) {
465→        const catalogEntry = actionCatalog.find((item) => item.id === action.id);
466→        const mergedAction = { ...(catalogEntry || {}), ...action };
467→        const result = await executeAction(mergedAction, { contextPayload });
468→        if (result?.ok && result?.result) {
469→          const summary = JSON.stringify(result.result, null, 2);
470→          sendCanvasMessage(
471→            `[Tool Result: ${action.label}]\n\`\`\`json\n${summary}\n\`\`\`\n위 결과를 바탕으로 설명해줘.`
472→          );
473→        }
474→        return;
475→      }
476→
477→      if (action?.type === 'navigate' && action?.id) {
478→        executeAction(action, { contextPayload });
479→        return;
480→      }
481→
482→      const nextPrompt = action?.prompt || action?.label || '';
483→      if (!nextPrompt) return;
484→      sendCanvasMessage(nextPrompt);
485→    },
486→    [actionCatalog, contextPayload, executeAction, sendCanvasMessage],
487→  );
488→
489→  const handleAskSelectedText = useCallback(
490→    (selectedText) => {
491→      const normalized = String(selectedText || '').trim();
492→      if (!normalized) return;
493→      const quotedPrompt = `다음 내용을 현재 맥락에서 설명해줘:\n"""${normalized}"""`;
494→      sendCanvasMessage(quotedPrompt);
495→    },
496→    [sendCanvasMessage],
497→  );
498→
499→  const {
500→    chip: selectionChip,
501→    handleAsk: handleAskSelection,
502→  } = useSelectionAskPrompt({
503→    containerRef: selectableContentRef,
504→    enabled: true,
505→    onAsk: handleAskSelectedText,
506→    minLength: 2,
507→    maxLength: 280,
508→  });
509→
510→  const handleBack = useCallback(() => {
511→    if (window.history.length > 1) {
512→      navigate(-1);
513→      return;
514→    }
515→    navigate('/home', { replace: true });
516→  }, [navigate]);
517→
518→  const openHistory = useCallback(() => {
519→    navigate('/agent/history', {
520→      state: { mode, contextPayload },
521→    });
522→  }, [contextPayload, mode, navigate]);
523→
524→  const handlePinSession = useCallback(async () => {
525→    if (!activeSessionId || isSavingSession) return;
526→    setIsSavingSession(true);
527→    try {
528→      const response = await authFetch(`${API_BASE_URL}/api/v1/tutor/sessions/${activeSessionId}/pin`, {
529→        method: 'POST',
530→        headers: { 'Content-Type': 'application/json' },
531→        body: JSON.stringify({ pinned: true }),
532→      });
533→      if (!response.ok) throw new Error('pin_failed');
534→
535→      if (reviewTarget) {
536→        await learningApi.upsertProgress({
537→          content_type: reviewTarget.contentType,
538→          content_id: reviewTarget.contentId,
539→          status: 'viewed',
540→          progress_percent: 20,
541→        });
542→
543→        const titleCandidate = (
544→          contextPayload?.keywords?.[0]?.title
545→          || contextPayload?.case_title
546→          || contextPayload?.stock_name
547→          || selectedUserPrompt
548→          || canvasState.title
549→          || '복습 카드'
550→        );
551→        const snippet = (selectedTurn?.assistantText || '').replace(/\s+/g, ' ').trim().slice(0, 180);
552→        const iconKey = contextPayload?.keywords?.[0]?.icon_key || contextPayload?.icon_key || DEFAULT_HOME_ICON_KEY;
553→
554→        try {
555→          localStorage.setItem(
556→            `${REVIEW_META_PREFIX}${reviewTarget.contentType}:${reviewTarget.contentId}`,
557→            JSON.stringify({
558→              title: titleCandidate,
559→              icon_key: iconKey,
560→              last_summary_snippet: snippet,
561→              updated_at: new Date().toISOString(),
562→            }),
563→          );
564→        } catch {
565→          // ignore storage errors
566→        }
567→      }
568→
569→      await refreshSessions();
570→      showSwipeToast('이 대화를 홈/교육 복습 카드로 저장했어요.');
571→    } catch {
572→      showSwipeToast('대화 저장에 실패했어요. 잠시 후 다시 시도해 주세요.');
573→    } finally {
574→      setIsSavingSession(false);
575→    }
576→  }, [
577→    activeSessionId,
578→    canvasState.title,
579→    contextPayload,
580→    isSavingSession,
581→    refreshSessions,
582→    reviewTarget,
583→    selectedTurn?.assistantText,
584→    selectedUserPrompt,
585→    showSwipeToast,
586→  ]);
587→
588→  const handleStopGeneration = useCallback(() => {
589→    stopGeneration();
590→  }, [stopGeneration]);
591→
592→  const handleRegenerate = useCallback(() => {
593→    if (canRegenerate) {
594→      regenerateLastResponse({
595→        difficulty: settings?.difficulty || 'beginner',
596→        chatOptions,
597→        contextInfoOverride: buildContextInfoForPrompt(selectedUserPrompt || initialPrompt),
598→      }).catch(() => {});
599→      return;
600→    }
601→
602→    if (selectedUserPrompt) {
603→      sendCanvasMessage(selectedUserPrompt);
604→    }
605→  }, [
606→    canRegenerate,
607→    buildContextInfoForPrompt,
608→    chatOptions,
609→    initialPrompt,
610→    regenerateLastResponse,
611→    sendCanvasMessage,
612→    selectedUserPrompt,
613→    settings?.difficulty,
614→  ]);
615→
616→  const swipeProgress = Math.min(100, Math.round((Math.abs(horizontalDelta) / HORIZONTAL_SWIPE_THRESHOLD_PX) * 100));
617→  const statusSubline = selectedTurn?.model
618→    ? `${canvasState.aiStatus} · ${selectedTurn.model}`
619→    : canvasState.aiStatus;
620→  const guardrailNotice = selectedTurn?.guardrailNotice || '';
621→  const phaseProgressByPhase = {
622→    thinking: 26,
623→    tool_call: 52,
624→    answering: 78,
625→    notice: 42,
626→    stopped: 100,
627→    error: 100,
628→    idle: 100,
629→  };
630→  const homeProgress = isStreamingActive
