  1→import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
  2→import { useLocation, useNavigate } from 'react-router-dom';
  3→import { API_BASE_URL, fetchJson, postJson } from '../api/client';
  4→import { usePortfolio } from '../contexts/PortfolioContext';
  5→import buildActionCatalog from '../utils/agent/buildActionCatalog';
  6→import { trackEvent, TRACK_EVENTS } from '../utils/analytics';
  7→
  8→const RESET_DELAY_MS = 1400;
  9→
 10→function isHighRisk(action) {
 11→  return action?.risk === 'high';
 12→}
 13→
 14→export default function useAgentControlOrchestrator({
 15→  mode = 'home',
 16→  stockContext = null,
 17→}) {
 18→  const location = useLocation();
 19→  const navigate = useNavigate();
 20→  const resetTimerRef = useRef(null);
 21→  const { refreshPortfolio } = usePortfolio();
 22→
 23→  const [controlState, setControlState] = useState({
 24→    phase: 'idle',
 25→    text: '대기 중',
 26→    activeActionId: null,
 27→  });
 28→
 29→  // 자동 실행 모드 — 켜면 고위험/네비게이션 확인 없이 바로 실행
 30→  const [autoMode, setAutoMode] = useState(false);
 31→
 32→  // 확인 대기 중인 액션 (ActionConfirmDialog에 표시)
 33→  const [pendingAction, setPendingAction] = useState(null);
 34→
 35→  const actionCatalog = useMemo(
 36→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext }),
 37→    [location.pathname, mode, stockContext],
 38→  );
 39→
 40→  const NAV_ACTION_IDS = ['nav_home', 'nav_portfolio', 'nav_education'];
 41→
 42→  const suggestedActions = useMemo(
 43→    () => actionCatalog
 44→      .filter((item) => item.risk === 'low' && !NAV_ACTION_IDS.includes(item.id))
 45→      .slice(0, 2),
 46→    [actionCatalog],
 47→  );
 48→
 49→  const traySummary = useMemo(() => {
 50→    if (mode === 'stock') {
 51→      return stockContext?.stock_name
 52→        ? `${stockContext.stock_name} 컨텍스트 기준으로 바로 조작할 수 있어요.`
 53→        : '투자 컨텍스트에서 바로 이동/분석을 실행할 수 있어요.';
 54→    }
 55→
 56→    if (mode === 'education') {
 57→      return '학습 화면에서 복습/이동을 바로 실행할 수 있어요.';
 58→    }
 59→
 60→    return '현재 화면 맥락으로 이동/실행을 바로 도와드릴게요.';
 61→  }, [mode, stockContext?.stock_name]);
 62→
 63→  const setTransientState = useCallback((nextState, fallbackState = { phase: 'idle', text: '대기 중', activeActionId: null }) => {
 64→    setControlState(nextState);
 65→
 66→    if (resetTimerRef.current) {
 67→      clearTimeout(resetTimerRef.current);
 68→    }
 69→
 70→    resetTimerRef.current = setTimeout(() => {
 71→      setControlState(fallbackState);
 72→    }, RESET_DELAY_MS);
 73→  }, []);
 74→
 75→  useEffect(() => {
 76→    return () => {
 77→      if (resetTimerRef.current) {
 78→        clearTimeout(resetTimerRef.current);
 79→      }
 80→    };
 81→  }, []);
 82→
 83→  // 실제 액션 실행 로직 (확인 절차 이후 호출)
 84→  const _doExecuteAction = useCallback(async (action, options = {}) => {
 85→    const previousPath = location.pathname;
 86→    const contextPayload = options.contextPayload || null;
 87→    const params = action.params || {};
 88→
 89→    setControlState({ phase: 'running', text: `${action.label} 실행 중...`, activeActionId: action.id });
 90→
 91→    try {
 92→      let result = null;
 93→
 94→      switch (action.id) {
 95→        case 'nav_home':
 96→          navigate('/home');
 97→          break;
 98→        case 'nav_portfolio':
 99→          navigate('/portfolio');
100→          break;
101→        case 'nav_education':
102→          navigate('/education');
103→          break;
104→        case 'nav_profile':
105→          navigate('/my');
106→          break;
107→        case 'nav_search':
108→          navigate('/home', { state: { openSearch: true } });
109→          break;
110→        case 'nav_feedback':
111→          navigate('/feedback');
112→          break;
113→        case 'start_quiz':
114→          navigate('/education', { state: { openQuiz: true } });
115→          break;
116→        case 'open_agent_history':
117→          navigate('/agent/history', { state: { mode, contextPayload } });
118→          break;
119→        case 'open_learning_history':
120→          navigate('/education/archive');
121→          break;
122→        case 'open_home_issue_agent':
123→          navigate('/agent', {
124→            state: {
125→              mode: 'home',
126→              initialPrompt: options.prompt || '오늘의 이슈 핵심만 정리해줘',
127→              contextPayload,
128→              resetConversation: location.pathname !== '/agent',
129→            },
130→          });
131→          break;
132→        case 'open_stock_agent': {
133→          if (!stockContext?.stock_code && !contextPayload?.stock_code) {
134→            throw new Error('종목 컨텍스트가 없습니다.');
135→          }
136→          navigate('/agent', {
137→            state: {
138→              mode: 'stock',
139→              stockContext: stockContext || contextPayload,
140→              initialPrompt: options.prompt || `${(stockContext || contextPayload).stock_name || '선택 종목'} 체크포인트를 요약해줘`,
141→              resetConversation: location.pathname !== '/agent',
142→            },
143→          });
144→          break;
145→        }
146→        case 'check_portfolio': {
147→          result = await fetchJson(`${API_BASE_URL}/api/v1/portfolio/summary`);
148→          break;
149→        }
150→        case 'check_stock_price': {
151→          const code = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
152→          if (!code) throw new Error('종목 코드가 없습니다.');
153→          result = await fetchJson(`${API_BASE_URL}/api/v1/trading/stocks/${code}`);
154→          break;
155→        }
156→        case 'check_stock_lookup': {
157→          const query = String(
158→            params.query
159→            || params.stock_name
160→            || stockContext?.stock_name
161→            || contextPayload?.stock_name
162→            || options.prompt
163→            || ''
164→          ).trim();
165→          if (!query) throw new Error('검색어가 없습니다.');
166→          const response = await fetchJson(`${API_BASE_URL}/api/v1/trading/search?q=${encodeURIComponent(query)}`);
167→          result = {
168→            query,
169→            count: Number(response?.count || 0),
170→            results: Array.isArray(response?.results) ? response.results.slice(0, 5) : [],
171→          };
172→          break;
173→        }
174→        case 'buy_stock': {
175→          const buyCode = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
176→          if (!buyCode) throw new Error('종목 코드가 없습니다.');
177→          const priceData = await fetchJson(`${API_BASE_URL}/api/v1/trading/stocks/${buyCode}`);
178→          const buyPrice = priceData?.current_price || priceData?.price;
179→          if (!buyPrice) throw new Error('시세를 가져올 수 없습니다.');
180→          const buyQty = params.quantity || 1;
181→          const buyName = params.stock_name || stockContext?.stock_name || contextPayload?.stock_name || buyCode;
182→          result = await postJson(`${API_BASE_URL}/api/v1/trading/order`, {
183→            stock_code: buyCode,
184→            stock_name: buyName,
185→            order_type: 'buy',
186→            quantity: buyQty,
187→            order_kind: 'market',
188→          });
189→          trackEvent(TRACK_EVENTS.TRADE_EXECUTE, { stock_code: buyCode, order_type: 'buy', quantity: buyQty });
190→          await refreshPortfolio(true);
191→          break;
192→        }
193→        case 'sell_stock': {
194→          const sellCode = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
195→          if (!sellCode) throw new Error('종목 코드가 없습니다.');
196→          const sellPriceData = await fetchJson(`${API_BASE_URL}/api/v1/trading/stocks/${sellCode}`);
197→          const sellPrice = sellPriceData?.current_price || sellPriceData?.price;
198→          if (!sellPrice) throw new Error('시세를 가져올 수 없습니다.');
199→          const sellQty = params.quantity || 1;
200→          const sellName = params.stock_name || stockContext?.stock_name || contextPayload?.stock_name || sellCode;
201→          result = await postJson(`${API_BASE_URL}/api/v1/trading/order`, {
202→            stock_code: sellCode,
203→            stock_name: sellName,
204→            order_type: 'sell',
205→            quantity: sellQty,
206→            order_kind: 'market',
207→          });
208→          trackEvent(TRACK_EVENTS.TRADE_EXECUTE, { stock_code: sellCode, order_type: 'sell', quantity: sellQty });
209→          await refreshPortfolio(true);
210→          break;
211→        }
212→        case 'limit_buy_stock': {
213→          const code = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
214→          if (!code) throw new Error('종목 코드가 없습니다.');
215→          const targetPrice = params.target_price;
216→          if (!targetPrice) throw new Error('지정가가 필요합니다.');
217→          const qty = params.quantity || 1;
218→          const name = params.stock_name || stockContext?.stock_name || contextPayload?.stock_name || code;
219→          result = await postJson(`${API_BASE_URL}/api/v1/trading/order`, {
220→            stock_code: code,
221→            stock_name: name,
222→            order_type: 'buy',
223→            quantity: qty,
224→            order_kind: 'limit',
225→            target_price: targetPrice,
226→          });
227→          await refreshPortfolio(true);
228→          break;
229→        }
230→        case 'short_sell_stock': {
231→          const code = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
232→          if (!code) throw new Error('종목 코드가 없습니다.');
233→          const priceData = await fetchJson(`${API_BASE_URL}/api/v1/trading/stocks/${code}`);
234→          const price = priceData?.current_price || priceData?.price;
235→          if (!price) throw new Error('시세를 가져올 수 없습니다.');
236→          const qty = params.quantity || 1;
237→          const name = params.stock_name || stockContext?.stock_name || contextPayload?.stock_name || code;
238→          result = await postJson(`${API_BASE_URL}/api/v1/trading/order`, {
239→            stock_code: code,
240→            stock_name: name,
241→            order_type: 'sell',
242→            quantity: qty,
243→            order_kind: 'market',
244→            position_side: 'short',
245→          });
246→          await refreshPortfolio(true);
247→          break;
248→        }
249→        case 'open_external_stock_info': {
250→          const code = params.stock_code || stockContext?.stock_code || contextPayload?.stock_code;
251→          if (!code) throw new Error('종목 코드가 없습니다.');
252→          window.open(`https://finance.naver.com/item/main.nhn?code=${code}`, '_blank', 'noopener,noreferrer');
253→          break;
254→        }
255→        default:
256→          throw new Error('지원하지 않는 동작입니다.');
257→      }
258→
259→      setTransientState({ phase: 'success', text: `${action.label} 완료`, activeActionId: action.id });
260→      return { ok: true, result };
261→    } catch (error) {
262→      if (action.type !== 'tool' && action.risk === 'low') {
263→        navigate(previousPath, { replace: true });
264→      }
265→      setTransientState({ phase: 'error', text: error?.message || '실행에 실패했습니다.', activeActionId: action.id });
266→      return { ok: false, reason: 'execution_error', error };
267→    }
268→  }, [location.pathname, mode, navigate, refreshPortfolio, setTransientState, stockContext]);
269→
270→  // 외부에서 호출하는 진입점 — 확인이 필요하면 pendingAction에 저장
271→  const executeAction = useCallback(async (action, options = {}) => {
272→    if (!action?.id) return { ok: false, reason: 'invalid_action' };
273→
274→    // 자동 모드가 아니고, 고위험 액션이면 확인 요청
275→    if (!autoMode && isHighRisk(action)) {
276→      setPendingAction({ action, options });
277→      return { ok: false, reason: 'pending_confirmation' };
278→    }
279→
280→    return _doExecuteAction(action, options);
281→  }, [autoMode, _doExecuteAction]);
282→
283→  // ActionConfirmDialog 버튼 핸들러
284→  const confirmPendingAction = useCallback((confirmMode) => {
285→    // confirmMode: 'confirm' | 'auto' | 'cancel'
286→    const pending = pendingAction;
287→    setPendingAction(null);
288→
289→    if (confirmMode === 'cancel') return;
290→    if (confirmMode === 'auto') setAutoMode(true);
291→
292→    if (pending?.action) {
293→      _doExecuteAction(pending.action, pending.options);
294→    }
295→  }, [pendingAction, _doExecuteAction]);
296→
297→  return {
298→    actionCatalog,
299→    suggestedActions,
300→    traySummary,
301→    controlState,
302→    isAgentControlling: controlState.phase === 'running',
303→    executeAction,
304→    autoMode,
305→    setAutoMode,
306→    pendingAction,
307→    confirmPendingAction,
308→  };
309→}
