  1→import { useCallback, useEffect, useState } from 'react';
  2→
  3→function normalizeSelectionText(text) {
  4→  if (typeof text !== 'string') return '';
  5→  return text.replace(/\s+/g, ' ').trim();
  6→}
  7→
  8→function hasMeaningfulText(text) {
  9→  return /[A-Za-z0-9가-힣]/.test(text);
 10→}
 11→
 12→export default function useSelectionAskPrompt({
 13→  containerRef,
 14→  onAsk,
 15→  enabled = true,
 16→  minLength = 10,
 17→  maxLength = 280,
 18→}) {
 19→  const [chip, setChip] = useState({
 20→    visible: false,
 21→    text: '',
 22→    left: 0,
 23→    top: 0,
 24→  });
 25→
 26→  const clearChip = useCallback(() => {
 27→    setChip((prev) => (prev.visible ? { ...prev, visible: false } : prev));
 28→  }, []);
 29→
 30→  const evaluateSelection = useCallback(() => {
 31→    if (!enabled || !containerRef?.current) {
 32→      clearChip();
 33→      return;
 34→    }
 35→
 36→    const selection = window.getSelection();
 37→    if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
 38→      clearChip();
 39→      return;
 40→    }
 41→
 42→    const range = selection.getRangeAt(0);
 43→    const anchor = range.startContainer;
 44→    const focus = range.endContainer;
 45→    const container = containerRef.current;
 46→
 47→    if (!container.contains(anchor) || !container.contains(focus)) {
 48→      clearChip();
 49→      return;
 50→    }
 51→
 52→    const normalized = normalizeSelectionText(selection.toString());
 53→    if (
 54→      !normalized
 55→      || normalized.length < minLength
 56→      || normalized.length > maxLength
 57→      || !hasMeaningfulText(normalized)
 58→    ) {
 59→      clearChip();
 60→      return;
 61→    }
 62→
 63→    const rect = range.getBoundingClientRect();
 64→    const viewportWidth = window.innerWidth || 390;
 65→    const left = Math.min(Math.max(rect.left + (rect.width / 2), 56), viewportWidth - 56);
 66→    const preferredTop = rect.top - 42;
 67→    const top = preferredTop >= 72 ? preferredTop : rect.bottom + 14;
 68→
 69→    setChip({
 70→      visible: true,
 71→      text: normalized,
 72→      left,
 73→      top,
 74→    });
 75→  }, [clearChip, containerRef, enabled, maxLength, minLength]);
 76→
 77→  const handleAsk = useCallback(() => {
 78→    if (!chip.visible || !chip.text || typeof onAsk !== 'function') return;
 79→    onAsk(chip.text);
 80→    try {
 81→      const selection = window.getSelection();
 82→      selection?.removeAllRanges();
 83→    } catch {
 84→      // ignore selection clear errors
 85→    }
 86→    clearChip();
 87→  }, [chip.text, chip.visible, clearChip, onAsk]);
 88→
 89→  useEffect(() => {
 90→    if (!enabled) {
 91→      clearChip();
 92→      return undefined;
 93→    }
 94→
 95→    const handleSelectionChange = () => {
 96→      evaluateSelection();
 97→    };
 98→    const handlePointerUp = () => {
 99→      evaluateSelection();
100→    };
101→    const handleScroll = () => {
102→      clearChip();
103→    };
104→
105→    document.addEventListener('selectionchange', handleSelectionChange);
106→    document.addEventListener('mouseup', handlePointerUp);
107→    document.addEventListener('touchend', handlePointerUp);
108→    window.addEventListener('scroll', handleScroll, { passive: true });
109→
110→    return () => {
111→      document.removeEventListener('selectionchange', handleSelectionChange);
112→      document.removeEventListener('mouseup', handlePointerUp);
113→      document.removeEventListener('touchend', handlePointerUp);
114→      window.removeEventListener('scroll', handleScroll);
115→    };
116→  }, [clearChip, enabled, evaluateSelection]);
117→
118→  return {
119→    chip,
120→    clearChip,
121→    handleAsk,
122→  };
123→}
