 54→  const { messages, agentStatus, isStreamingActive } = useTutor();
 55→  const { openTutor } = useTutorUI();
 56→  const { keyboardOffset, shouldHideBottomNav } = useKeyboardInset();
 57→  const hasActiveSession = Array.isArray(messages) && messages.length > 0;
 58→  const isAgentRoute = location.pathname.startsWith('/agent');
 59→  const hideBottomNav = shouldHideBottomNav;
 60→
 61→  useEffect(() => {
 62→    try {
 63→      localStorage.setItem(SEARCH_TOGGLE_KEY, searchEnabled ? '1' : '0');
 64→    } catch {
 65→      // ignore storage errors
 66→    }
 67→  }, [searchEnabled]);
 68→
 69→  useEffect(() => {
 70→    try {
 71→      const hasStoredValue = localStorage.getItem(SEARCH_TOGGLE_KEY);
 72→      if (hasStoredValue === null) {
 73→        setSearchEnabled(mode === 'stock');
 74→      }
 75→    } catch {
 76→      setSearchEnabled(mode === 'stock');
 77→    }
 78→  }, [mode]);
 79→
 80→  useEffect(() => {
 81→    document.documentElement.style.setProperty('--keyboard-offset', `${keyboardOffset}px`);
 82→    return () => {
 83→      document.documentElement.style.setProperty('--keyboard-offset', '0px');
 84→    };
 85→  }, [keyboardOffset]);
 86→
 87→  const baseContextPayload = useMemo(() => {
 88→    if (mode === 'stock' && location.state?.stockContext) {
 89→      return location.state.stockContext;
 90→    }
 91→
 92→    if (mode === 'home') {
 93→      return readSessionJson('adelie_home_context');
 94→    }
 95→
 96→    if (mode === 'education') {
 97→      return readSessionJson('adelie_education_context');
 98→    }
 99→
100→    return null;
101→  }, [location.state, mode]);
102→
103→  const {
104→    controlState,
105→    isAgentControlling,
106→    actionCatalog: orchestratorActionCatalog,
107→    executeAction,
108→    pendingAction,
109→    confirmPendingAction,
110→  } = useAgentControlOrchestrator({
111→    mode,
112→    stockContext: baseContextPayload,
113→  });
114→
115→  const actionCatalog = useMemo(
116→    () => buildActionCatalog({ pathname: location.pathname, mode, stockContext: baseContextPayload }),
117→    [baseContextPayload, location.pathname, mode],
118→  );
119→
120→  const buildControlContextPayload = useCallback((prompt = '') => {
121→    const uiSnapshot = buildUiSnapshot({
