  1→/**
  2→ * 공통 HTTP 클라이언트 설정 - 중앙 에러 핸들링 포함
  3→ */
  4→import { API_BASE_URL } from '../config';
  5→
  6→export { API_BASE_URL };
  7→
  8→const AUTH_BYPASS_PATHS = [
  9→  '/api/v1/auth/login',
 10→  '/api/v1/auth/register',
 11→  '/api/v1/auth/refresh',
 12→];
 13→
 14→let refreshPromise = null;
 15→
 16→const getStoredAccessToken = () => localStorage.getItem('token') || localStorage.getItem('authToken') || '';
 17→const getStoredRefreshToken = () => localStorage.getItem('refreshToken') || '';
 18→
 19→const toPathname = (url) => {
 20→  try {
 21→    const value = typeof url === 'string' ? url : url?.url;
 22→    if (!value) return '';
 23→    return new URL(value, window.location.origin).pathname;
 24→  } catch {
 25→    return '';
 26→  }
 27→};
 28→
 29→const isAuthBypassRequest = (url) => {
 30→  const pathname = toPathname(url);
 31→  return AUTH_BYPASS_PATHS.some((path) => pathname.endsWith(path));
 32→};
 33→
 34→const mergeAuthHeaders = (headers, token = getStoredAccessToken()) => {
 35→  const merged = new Headers(headers || {});
 36→  if (token && !merged.has('Authorization')) {
 37→    merged.set('Authorization', `Bearer ${token}`);
 38→  }
 39→  return merged;
 40→};
 41→
 42→/** 인증 실패 시 토큰 제거 + 자동 로그아웃 이벤트 발행 + 로그인 화면 이동 */
 43→const handleAuthFailure = () => {
 44→  localStorage.removeItem('token');
 45→  localStorage.removeItem('authToken');
 46→  localStorage.removeItem('refreshToken');
 47→  window.dispatchEvent(new Event('auth:logout'));
 48→  if (!window.location.pathname.startsWith('/auth')) {
 49→    window.location.assign('/auth');
 50→  }
 51→};
 52→
 53→const readErrorMessage = async (response) => {
 54→  const errorData = await response.json().catch(() => ({}));
 55→  return errorData.detail || errorData.message || `요청 실패 (${response.status})`;
 56→};
 57→
 58→const refreshAccessToken = async () => {
 59→  if (refreshPromise) return refreshPromise;
 60→  refreshPromise = (async () => {
 61→    const refreshToken = getStoredRefreshToken();
 62→    if (!refreshToken) throw new Error('refresh token not found');
 63→
 64→    const response = await fetch(`${API_BASE_URL}/api/v1/auth/refresh`, {
 65→      method: 'POST',
 66→      headers: { 'Content-Type': 'application/json' },
 67→      body: JSON.stringify({ refreshToken }),
 68→    });
 69→
 70→    if (!response.ok) {
 71→      const message = await readErrorMessage(response);
 72→      throw new Error(message);
 73→    }
 74→
 75→    const tokens = await response.json();
 76→    if (!tokens?.accessToken || !tokens?.refreshToken) {
 77→      throw new Error('invalid refresh response');
 78→    }
 79→
 80→    localStorage.setItem('token', tokens.accessToken);
 81→    localStorage.removeItem('authToken');
 82→    localStorage.setItem('refreshToken', tokens.refreshToken);
 83→
 84→    return tokens.accessToken;
 85→  })().finally(() => {
 86→    refreshPromise = null;
 87→  });
 88→
 89→  return refreshPromise;
 90→};
 91→
 92→/** 인증 포함 fetch (401 시 refresh 후 원요청 1회 재시도, 10초 타임아웃 포함) */
 93→export const authFetch = async (url, options = {}, canRetry = true) => {
 94→  const controller = new AbortController();
 95→  const timeoutId = setTimeout(() => controller.abort(), 10_000);
 96→
 97→  try {
 98→    const response = await fetch(url, {
 99→      ...options,
100→      headers: mergeAuthHeaders(options.headers),
101→      signal: controller.signal,
102→    });
103→
104→    if (response.status !== 401 || !canRetry || isAuthBypassRequest(url)) {
105→      return response;
106→    }
107→
108→    try {
109→      const nextAccessToken = await refreshAccessToken();
110→      const retried = await fetch(url, {
111→        ...options,
112→        headers: mergeAuthHeaders(options.headers, nextAccessToken),
113→        signal: controller.signal,
114→      });
115→      if (retried.status === 401) {
116→        handleAuthFailure();
117→      }
118→      return retried;
119→    } catch (error) {
120→      handleAuthFailure();
121→      throw error;
122→    }
123→  } finally {
124→    clearTimeout(timeoutId);
125→  }
126→};
