 50→    } else if (e.key === 'ArrowUp') {
 51→      e.preventDefault();
 52→      setActiveIndex((prev) => (prev - 1 + filtered.length) % filtered.length);
 53→    } else if (e.key === 'Enter') {
 54→      e.preventDefault();
 55→      onSelect(filtered[activeIndex]);
 56→    } else if (e.key === 'Escape') {
 57→      e.preventDefault();
 58→      onClose();
 59→    }
 60→  }, [visible, filtered, activeIndex, onSelect, onClose]);
