 79→}
 80→
 81→function normalizeUiActions(uiActions) {
 82→  if (!Array.isArray(uiActions)) return [];
 83→
 84→  return uiActions
 85→    .map((action, index) => {
 86→      if (!action) return null;
 87→      if (typeof action === 'string') {
 88→        return {
 89→          id: `action-${index}`,
