 99→      return {
100→        id: action.id || `action-${index}`,
101→        label,
102→        type: action.type || 'prompt',
103→        prompt: action.prompt || label,
104→        params: action.params || {},
105→      };
106→    })
107→    .filter(Boolean);
108→}
109→
110→function buildModeLabel(mode) {
111→  if (mode === 'stock') return '종목 컨텍스트';
112→  if (mode === 'education') return '학습 컨텍스트';
113→  if (mode === 'my') return 'MY 컨텍스트';
114→  return '홈 컨텍스트';
115→}
116→
117→function normalizeSources(sources) {
118→  if (!Array.isArray(sources)) return [];
119→
120→  return sources
121→    .filter((item) => item && typeof item === 'object')
122→    .map((item) => ({
123→      title: String(item.title || item.content || '출처').trim(),
124→      url: String(item.url || '').trim(),
125→      source_kind: String(item.source_kind || item.type || 'internal').trim(),
126→      is_reachable: item.is_reachable === null || item.is_reachable === undefined
127→        ? null
128→        : Boolean(item.is_reachable),
129→      metrics: item.metrics && typeof item.metrics === 'object' ? item.metrics : null,
130→    }));
131→}
132→
133→function collectMetricRows(sources) {
134→  const labelMap = {
135→    revenue: '매출액',
136→    operating_income: '영업이익',
137→    net_income: '당기순이익',
138→    total_assets: '자산총계',
139→    total_liabilities: '부채총계',
140→  };
141→
142→  for (const source of sources) {
143→    if (!source?.metrics) continue;
144→    const rows = Object.entries(source.metrics)
145→      .filter(([key, value]) => labelMap[key] && Number.isFinite(Number(value)))
146→      .map(([key, value]) => ({
147→        key,
148→        label: labelMap[key],
