193→    : [];
194→
195→  const keyPoint = structured?.summary || sentences[0] || paragraphs[0] || '';
196→  const explanation = sentences.slice(1, 3).join(' ') || paragraphs[1] || '';
197→  const bullets = hasStructuredMarkdown ? extractBullets(assistantText, sentences) : [];
