### `client.js` (162 lines)

**Request Wrapper** (auto-auth, retry, timeout):
```javascript
export const authFetch = async (url, options = {}, canRetry = true) => {
  // 1. Merge Authorization header from localStorage
  const token = localStorage.getItem('token') || localStorage.getItem('authToken');
  headers.set('Authorization', `Bearer ${token}`);

  // 2. 10-second timeout
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), 10_000);

  try {
    const response = await fetch(url, {...options, headers, signal});

    // 3. 401 → refresh → retry once
    if (response.status === 401 && canRetry && !isAuthBypassPath(url)) {
      const nextToken = await refreshAccessToken();  // POST /api/v1/auth/refresh
      return fetch(url, {...options, headers: mergeAuthHeaders(options.headers, nextToken)});
    }

    // 4. 401 still → logout
    if (response.status === 401) {
      handleAuthFailure();  // Remove tokens, dispatch 'auth:logout' event
    }

    return response;
  } finally {
    clearTimeout(timeoutId);
  }
};

export const fetchJson = async (url) => {
  const response = await authFetch(url);
  if (!response.ok) throw new Error(await readErrorMessage(response));
  return response.json();
};

export const postJson = async (url, body) => {
  const response = await authFetch(url, {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify(body),
  });
  if (!response.ok) throw new Error(await readErrorMessage(response));
  return response.json();
};
```

