            </svg>
          </button>
        </div>

        {/* 선택 텍스트 */}
        {selectedText && (
          <div className="border-b border-gray-50 bg-gray-50/50 px-3 py-1.5">
            <p className="line-clamp-2 text-[11px] text-[#6B7684] italic">
              &ldquo;{selectedText}&rdquo;
