import { useEffect, useRef } from 'react';

export default function QuickQAPopover({
  isOpen,
  isLoading,
  result,
  selectedText,
  position,
  onClose,
  onAddToCanvas,
}) {
  const popoverRef = useRef(null);

  // 외부 클릭 닫기
  useEffect(() => {
